314→        /// <summary>
315→        /// Create new Papyrus application organization
316→        /// </summary>
317→        /// <param name="newOrg"><see cref="PapyrusAppOrg"/> representing new org</param>
318→        /// <returns>A <see cref="Task"/> representing the asynchronous operation.</returns>
319→        [Route("acl/organizations")]
320→        [HttpPost]
321→        public async Task<PapyrusAppOrg> CreatePapyrusAppOrganizationAsync(PapyrusAppOrg newOrg)
322→        {
323→            await this.CheckAdminPermissionAsync();
324→            var createdOrg = this.configSvc.CreatePapyrusAppOrganization(newOrg);
325→            return createdOrg;
326→        }
327→
328→        /// <summary>
329→        /// Update Papyrus application organization owners list
330→        /// </summary>
331→        /// <param name="updatedOrg"><see cref="PapyrusAppOrg"/> with an updated owners list</param>
332→        /// <returns>A <see cref="Task"/> representing the asynchronous operation.</returns>
333→        [Route("acl/organizations")]
334→        [HttpPut]
335→        public async Task<PapyrusAppOrg> UpdatePapyrusAppOrganizationOwnersListAsync(PapyrusAppOrg updatedOrg)
336→        {
337→            // Find the current org by ID
338→            var allOrgs = this.configSvc.GetPapyrusAppOrganizations();
339→            var currentOrg = allOrgs?.FirstOrDefault(o => o.Id == updatedOrg.Id);
340→            if (currentOrg == null)
341→            {
342→                throw new UserException($"No organization found with ID {updatedOrg.Id}");
343→            }
344→
345→            await this.CheckOwnerOrAdminPermissionAsync(currentOrg.Owners);
346→            var updatedResult = this.configSvc.UpdatePapyrusAppOrganizationOwnersList(updatedOrg);
347→            return updatedResult;
348→        }
349→    }
