 28→    /// <summary>
 29→    /// Kusto-backed Service Tree node lookup.
 30→    /// </summary>
 31→    public sealed class ServiceTreeKustoClient : IServiceTreeNodeLookup
 32→    {
 33→        private readonly ServiceTreeKustoOptions kustoOptions;
 34→        private readonly ServiceTreeClientOptions authOptions;
 35→        private readonly ILogger<ServiceTreeKustoClient> logger;
 36→        private readonly TokenCredential? tokenCredential;
 37→        private readonly string tokenScope;
 38→        private readonly bool isConfigured;
 39→        private readonly int maxBatchSize;
 40→        private readonly int maxConcurrency = 4;
 41→
 42→        /// <summary>
 43→        /// Initializes a new instance of the <see cref="ServiceTreeKustoClient"/> class.
 44→        /// </summary>
 45→        /// <param name="kustoOptions">Kusto options.</param>
 46→        /// <param name="authOptions">Auth options.</param>
 47→        /// <param name="logger">Logger instance.</param>
 48→        /// <param name="credentialFactory">Optional credential factory for cross-tenant support.</param>
 49→        public ServiceTreeKustoClient(
 50→            ServiceTreeKustoOptions kustoOptions,
 51→            ServiceTreeClientOptions authOptions,
 52→            ILogger<ServiceTreeKustoClient> logger,
 53→            ICredentialFactory credentialFactory = null)
 54→        {
 55→            this.kustoOptions = kustoOptions ?? throw new ArgumentNullException(nameof(kustoOptions));
 56→            this.authOptions = authOptions ?? throw new ArgumentNullException(nameof(authOptions));
 57→            this.logger = logger ?? throw new ArgumentNullException(nameof(logger));
 58→
 59→            if (string.IsNullOrWhiteSpace(this.kustoOptions.ClusterUri)
 60→                || string.IsNullOrWhiteSpace(this.kustoOptions.Database))
 61→            {
 62→                this.logger.LogWarning("ServiceTreeKustoClient: Kusto cluster or database is not configured.");
 63→                this.isConfigured = false;
 64→                return;
 65→            }
 66→
 67→            this.tokenScope = this.ResolveTokenScope(this.kustoOptions);
 68→            if (string.IsNullOrWhiteSpace(this.tokenScope))
 69→            {
 70→                this.logger.LogWarning("ServiceTreeKustoClient: Token scope is not configured.");
 71→                this.isConfigured = false;
 72→                return;
 73→            }
 74→
 75→            this.tokenCredential = this.ResolveTokenCredential(credentialFactory, this.authOptions);
 76→            if (this.tokenCredential == null)
 77→            {
 78→                this.logger.LogWarning("ServiceTreeKustoClient: No AAD credentials configured for Kusto.");
 79→                this.isConfigured = false;
 80→                return;
 81→            }
 82→
 83→            this.maxBatchSize = this.kustoOptions.MaxBatchSize <= 0 ? 200 : this.kustoOptions.MaxBatchSize;
 84→            this.isConfigured = true;
 85→        }
 86→
 87→        /// <inheritdoc/>
 88→        public async Task<IReadOnlyDictionary<string, ServiceTreeNode>> GetNodesByIdsAsync(
 89→            IEnumerable<string> ids,
 90→            CancellationToken cancellationToken)
 91→        {
 92→            var results = new ConcurrentDictionary<string, ServiceTreeNode>(StringComparer.OrdinalIgnoreCase);
 93→            if (!this.isConfigured)
 94→            {
 95→                return results;
 96→            }
 97→
 98→            var uniqueIds = (ids ?? Enumerable.Empty<string>())
 99→                .Where(id => !string.IsNullOrWhiteSpace(id))
100→                .Select(id => id.Trim())
101→                .Distinct(StringComparer.OrdinalIgnoreCase)
102→                .ToList();
103→
104→            if (uniqueIds.Count == 0)
105→            {
106→                return results;
107→            }
108→
109→            var batches = this.SplitStringBatches(uniqueIds, this.maxBatchSize);
110→            using var semaphore = new SemaphoreSlim(this.maxConcurrency);
111→            var tasks = batches.Select(async batch =>
112→            {
