616→        private TokenCredential? ResolveTokenCredential(
617→            ICredentialFactory? credentialFactory,
618→            ServiceTreeClientOptions options)
619→        {
620→            // When ICredentialFactory is available AND auth mode is DefaultAzureCredential,
621→            // use the factory for cross-tenant support (PME MSI → MSFT tenant token).
622→            if (credentialFactory != null
623→                && options.AuthenticationMode == ServiceTreeAuthenticationMode.DefaultAzureCredential)
624→            {
625→                try
626→                {
627→                    var cred = credentialFactory.CreateTokenCredential(AADTenant.MSFT);
628→                    this.logger.LogInformation(
629→                        "ServiceTreeKustoClient: Using ICredentialFactory for MSFT-tenant credential (type={CredType}).",
630→                        cred.GetType().Name);
631→                    return cred;
632→                }
633→                catch (Exception ex)
634→                {
635→                    this.logger.LogError(
636→                        ex,
637→                        "ServiceTreeKustoClient: ICredentialFactory.CreateTokenCredential failed.");
638→                    throw;
639→                }
640→            }
641→
642→            return this.CreateTokenCredential(options);
643→        }
644→
645→        private TokenCredential? CreateTokenCredential(ServiceTreeClientOptions options)
646→        {
647→            if (options.AuthenticationMode == ServiceTreeAuthenticationMode.DefaultAzureCredential)
648→            {
649→                return new DefaultAzureCredential(new DefaultAzureCredentialOptions
650→                {
651→                    ManagedIdentityClientId = string.IsNullOrWhiteSpace(options.AadClientId) ? null : options.AadClientId,
652→                });
653→            }
654→
655→            if (options.AuthenticationMode == ServiceTreeAuthenticationMode.Aad)
656→            {
657→                if (!string.IsNullOrWhiteSpace(options.AadClientSecret)
658→                    && !string.IsNullOrWhiteSpace(options.AadTenantId)
659→                    && !string.IsNullOrWhiteSpace(options.AadClientId))
660→                {
661→                    return new ClientSecretCredential(options.AadTenantId, options.AadClientId, options.AadClientSecret);
662→                }
663→
664→                if (!string.IsNullOrWhiteSpace(options.AadClientCertificateBase64)
665→                    && !string.IsNullOrWhiteSpace(options.AadTenantId)
666→                    && !string.IsNullOrWhiteSpace(options.AadClientId))
667→                {
668→#pragma warning disable CA2000 // Certificate lifetime is tied to the credential.
669→                    var cert = this.TryLoadAadCertificate(options);
670→#pragma warning restore CA2000
671→                    if (cert == null)
672→                    {
673→                        return null;
674→                    }
675→
676→                    return new ClientCertificateCredential(
677→                        options.AadTenantId,
678→                        options.AadClientId,
679→                        cert,
680→                        new ClientCertificateCredentialOptions { SendCertificateChain = true });
681→                }
682→
683→                if (!string.IsNullOrWhiteSpace(options.AadClientId))
684→                {
685→                    return new ManagedIdentityCredential(options.AadClientId);
686→                }
687→
688→                return new ManagedIdentityCredential();
689→            }
690→
691→            return null;
692→        }
